import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as a,f as r}from"./app-4ea9d5e7.js";const h={},t=r('<h1 id="_15-2025年中总结" tabindex="-1"><a class="header-anchor" href="#_15-2025年中总结" aria-hidden="true">#</a> #15 2025年中总结</h1><p>这是一个社会非常常见的现象。来来去去多少人，活在了这个坑里。</p><p>世界上有太多的元宇宙。</p><h2 id="一、" tabindex="-1"><a class="header-anchor" href="#一、" aria-hidden="true">#</a> 一、</h2><p>前段时间一个商场里，看到里面有一个玩具赛车店。店里一个非常巨大的赛道。</p><p>门口挂了一个标牌，里面用胶带纸写着时间排名前1、2、3的小朋友的名字。</p><p>后面应该又是有人打破前1了，于是又在第一名前面，再挂了一个第一名。尾巴地方列了大量的速度超过XX秒的选手的名称。</p><p>我的感觉是：</p><p>这不就是给小朋友编织一个小型的幻梦么。</p><p>这种小车，本质上没有太多技术，保养一次车子都要500元。</p><p>玩一个小时这个赛车需要多少钱呢？答案是100元。</p><p>商家的总成本非常低。</p><p>如果你想把这个速度提升上去，你就要多次练习。后面墙壁上还挂着小朋友的大头像，说是开这个赛车获得了市级的奖。</p><p>搞的和元宇宙一样。</p><p>在这个小型元宇宙，你赢了，可以获得no.1。</p><p>只要充钱就可以训练，只要买更好的设备你就可以变强。里面肯定是有一些技术的，但是这些技术也就仅仅用在这个赛道上。</p><p>你赢了这里，难道就真的是现实世界的赛车手了么？</p><p>市里面的奖项，不本身还是这个赛车店的母公司举办的么？</p><h2 id="二、" tabindex="-1"><a class="header-anchor" href="#二、" aria-hidden="true">#</a> 二、</h2><p>小红书有一个话题叫打赏上瘾，很难戒掉，只会越陷越深，很多大哥大姐实际享受的是送出礼物那一刻的感觉。</p><p>自己成为大哥的感觉最难戒掉。</p><p>直播间就是一个小元宇宙。你是大哥，榜一榜二。但是这种榜单本身不是可以无限增发么？</p><p>我可不可以搞一个打赏周榜？搞一个月榜？总榜？</p><p>甚至搞一个地区榜？</p><p>你充值成了榜一，踏着七彩祥云而来。这个元宇宙里面的所有人都看着你，都要喊一声，X哥来了。X哥今天来晚了。</p><h1 id="三、" tabindex="-1"><a class="header-anchor" href="#三、" aria-hidden="true">#</a> 三、</h1><p>我觉得 其实很多地方都是给你 营造一个元宇宙</p><p>职场也是，一个相对独立的环境，就是这样一个元宇宙。</p><p>职级本来只是一个数字而已。月度绩效和年度绩效其背后的本质也只是一个数字。</p><p>职场的操盘手让这个数字，和money挂钩起来。但是这数字仍旧只是一个数字啊。money不能无限增发，但是这个数字是可以无限增发的。</p><p>领导的器重和表扬，也只是一个&quot;感觉&quot;不代表利益本身，但是很多人就是对表扬上瘾。对批评害怕。然后去拼命加班，优化领导对自己的表扬。批评了一下，就仿佛饭都吃不好了。出一个线上Bug，宛如世界就要毁灭了。</p><p>本质上有人构建了一个环境，就要在这个体系内部收割你了。</p><p>小红花本来没有价值是可以批量增发的。</p><p>多少人打工打工着，目标从优化赚钱变成了，优化“领导”对自己的表扬。</p><p>本来应该优化的是总收入，但是有的人优化成了领导的表扬。</p><p>钱没有多少，荣誉奖励拿了一堆。每一个还都有一大堆故事可讲。</p><p>等到有一天公司核算利润，把你裁掉的时候，你这堆奖状，去和谁说故事？等到你的组长自己离开，或者你离开，你的这些“忠诚”找谁去兑现？</p><h1 id="四、" tabindex="-1"><a class="header-anchor" href="#四、" aria-hidden="true">#</a> 四、</h1><p>元宇宙错了么？看了上面，你可能以为我要批判元宇宙。不对！我真正想说的是，你应该自己去构建自己的元宇宙。</p><p>元宇宙的反面。</p><p>反面不是非元宇宙。反面是另一个元宇宙。真实世界为何是真实世界，因为不论如何，你都要回到真实世界来。</p><p>真实世界才是唯一的世界。你在任何一个世界里当了大哥，但是你终究是活在这个真实的世界里面的。</p><p>在直播间里，充值一停，感情归零。但是如果你在真实世界有家底，有可能直播间的充值，只是你的一次情感消费而已。</p><p>真实世界和虚拟世界的货币兑换，会高到很夸张的比例。</p><p>另一个角度，为何给自己一个舒服的环境很重要。因为任何人都是生活在周边的那个小环境中。</p><p>不要说你有多少钱，不要说别的。你最周围的环境，决定了你的生活质量。很多上海看似房产千万的人，生活质量就是不如云南总家产两百万的土老板。</p><p>那么，我们也要给自己找寻自己的元宇宙。</p><p>恩爱的伴侣，幸福的一家，友好的邻里，健康的生活。你生活在这个环境下，有什么别的负面信息，也可以很快的冲刷掉。</p>',48),d=[t];function n(i,o){return e(),a("div",null,d)}const _=p(h,[["render",n],["__file","16 元宇宙.html.vue"]]);export{_ as default};
